SELECT sample_id, percent_retained
FROM sieve_tests
WHERE percent_retained = (SELECT MAX(percent_retained) FROM sieve_tests);

SELECT AVG(soil_retained_gm) AS average_soil_retained_gm
FROM sieve_tests
WHERE diameter_mm = 60;

SELECT * 
FROM sieve_tests 
WHERE strftime('%Y-%m', test_date) = '2023-05';

SELECT location
FROM soil_samples
WHERE sample_id = 1;

SELECT COUNT(test_id)
FROM sieve_tests
WHERE test_id = 1;

SELECT * 
FROM test_results 
WHERE result_id = 10;

SELECT ss.soil_type
FROM soil_samples ss
JOIN sieve_tests st ON ss.sample_id = st.sample_id
WHERE st.percent_retained = (
    SELECT MAX(percent_retained) FROM sieve_tests
);

SELECT file_path 
FROM attachments 
WHERE test_id = 0;

SELECT action
FROM access_logs
LIMIT 10;

SELECT *
FROM test_methods
WHERE method_name = 'Sieve Analysis';
